// ========================================
// GL365 ServiceTitan Event Normalizer
// ========================================
// Maps ServiceTitan webhook payloads to GL365 journal format.
//
// ServiceTitan events:
//   job.scheduled    → booking_created
//   job.dispatched   → tech_dispatched
//   job.completed    → job_completed
//   job.cancelled    → booking_cancelled
//   customer.created → new_customer
//   estimate.sent    → estimate_sent
//   invoice.created  → invoice_created
//   payment.received → payment_received

const input = $input.first().json;
const event = input.event || input.type || '';
const data = input.data || input;

// Map ServiceTitan events to GL365 event types
const eventMap = {
  'job.scheduled': 'booking_created',
  'job.dispatched': 'tech_dispatched',
  'job.completed': 'job_completed',
  'job.cancelled': 'booking_cancelled',
  'customer.created': 'new_customer',
  'estimate.sent': 'estimate_sent',
  'invoice.created': 'invoice_created',
  'payment.received': 'payment_received'
};

// Determine importance
let importance = 'normal';
if (event === 'job.cancelled') importance = 'high';
if (event === 'payment.received') importance = 'normal';
if (event === 'job.completed') importance = 'normal';

// Determine sentiment
let sentiment = 'neutral';
if (event === 'job.completed') sentiment = 'positive';
if (event === 'payment.received') sentiment = 'positive';
if (event === 'job.cancelled') sentiment = 'negative';

// Extract customer info from ServiceTitan payload
const customer = data.customer || data.contact || {};
const job = data.job || data;

const normalized = {
  tenant_id: input.metadata?.tenant_id || '',
  contact_phone: customer.phone || customer.phoneNumber || customer.mobilePhone || '',
  contact_email: customer.email || '',
  contact_name: customer.name || [customer.firstName, customer.lastName].filter(Boolean).join(' ') || '',
  source: 'servicetitan',
  event_type: eventMap[event] || event || 'unknown',
  raw_summary: `ServiceTitan ${event}: ${job.summary || job.type || ''} for ${customer.name || 'customer'} at ${job.location?.address || ''}`.trim(),
  raw_data: input,
  sentiment,
  importance,
  // ServiceTitan-specific fields for the AI summary
  job_type: job.type || job.businessUnit || '',
  technician: job.technician?.name || job.assignedTo || '',
  job_total: job.total || job.invoiceTotal || '',
  job_address: job.location?.address || job.serviceAddress || '',
  job_id: job.id || job.jobNumber || ''
};

return [{ json: normalized }];

const input = $input.first().json;
const prevData = $('Normalize ServiceTitan Event').first().json;

let summary = '';
try {
  summary = input.choices?.[0]?.message?.content || prevData.raw_summary;
} catch {
  summary = prevData.raw_summary;
}

return [{ json: { ...prevData, summary: summary.trim().replace(/^["']|["']$/g, '') } }];
